// Gmail polling via IMAP-like approach using Gmail API search
// Since we don't have Gmail OAuth2 set up yet, this node
// prepares the Gmail API request parameters.
// When Gmail OAuth2 is configured, replace the HTTP Request
// node with a native Gmail node.

const lastHistoryId = $input.first().json.value || '0';
const now = new Date();
const hour = now.getUTCHours(); // Adjust for UK time

// Determine polling window
// Business hours: every 5 min, Off-hours: every 15 min
// For now we always run since schedule handles frequency

// Build Gmail search query for recent messages
// Using 'after' with epoch timestamp for last 10 minutes
const tenMinAgo = Math.floor((now.getTime() - 10 * 60 * 1000) / 1000);
const searchQuery = `in:inbox after:${tenMinAgo}`;

return [{
  json: {
    lastHistoryId,
    searchQuery,
    pollTimestamp: now.toISOString(),
    note: 'Gmail OAuth2 credential must be configured manually in n8n. This workflow structure is ready but Gmail nodes need credential binding.'
  }
}];

// Parse Gmail list response and check for messages
const input = $input.first().json;

// Handle case where Gmail credential is not configured yet
if (input.error || !input.body || !input.body.messages) {
  return [{ json: { hasMessages: false, messages: [], error: input.error || 'No messages or Gmail not configured' } }];
}

const messages = input.body.messages || [];
return [{ json: { hasMessages: messages.length > 0, messages, resultSizeEstimate: input.body.resultSizeEstimate || 0 } }];

// Split messages array into individual items for processing
const messages = $input.first().json.messages || [];
return messages.map(m => ({ json: { messageId: m.id, threadId: m.threadId } }));

// Parse Gmail message into structured email data
const msg = $input.first().json;

if (!msg.body || !msg.body.payload) {
  return [{ json: { error: 'Could not parse message', skip: true } }];
}

const payload = msg.body.payload;
const headers = payload.headers || [];

// Helper to get header value
const getHeader = (name) => {
  const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : null;
};

// Extract email address from "Name <email>" format
const extractEmail = (raw) => {
  if (!raw) return null;
  const match = raw.match(/<([^>]+)>/);
  return match ? match[1] : raw;
};

const extractName = (raw) => {
  if (!raw) return null;
  const match = raw.match(/^"?([^"<]+)"?\s*</);
  return match ? match[1].trim() : null;
};

// Extract body parts
let bodyPlain = '';
let bodyHtml = '';

const extractParts = (part) => {
  if (part.mimeType === 'text/plain' && part.body && part.body.data) {
    bodyPlain = Buffer.from(part.body.data, 'base64url').toString('utf-8');
  }
  if (part.mimeType === 'text/html' && part.body && part.body.data) {
    bodyHtml = Buffer.from(part.body.data, 'base64url').toString('utf-8');
  }
  if (part.parts) {
    part.parts.forEach(extractParts);
  }
};
extractParts(payload);

// Strip HTML for classification
let bodyStripped = bodyHtml
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

if (!bodyStripped && bodyPlain) bodyStripped = bodyPlain;

// Truncate for storage (keep first 10000 chars)
bodyStripped = bodyStripped.substring(0, 10000);

const fromRaw = getHeader('From');
const subject = getHeader('Subject') || '(no subject)';
const date = getHeader('Date');
const isReply = subject.toLowerCase().startsWith('re:') || !!getHeader('In-Reply-To');

// Check attachments
const attachmentTypes = [];
let hasIcs = false;
const checkAttachments = (part) => {
  if (part.filename && part.filename.length > 0) {
    attachmentTypes.push(part.mimeType);
    if (part.mimeType === 'application/ics' || part.filename.endsWith('.ics')) {
      hasIcs = true;
    }
  }
  if (part.parts) part.parts.forEach(checkAttachments);
};
checkAttachments(payload);

// Simple language detection (check for non-ASCII heavy content)
let detectedLanguage = 'en';
let languageConfidence = 0.9;
const nonAsciiRatio = (bodyStripped.replace(/[\x00-\x7F]/g, '').length) / Math.max(bodyStripped.length, 1);
if (nonAsciiRatio > 0.3) {
  detectedLanguage = 'unknown';
  languageConfidence = 0.5;
}

const gmailLabels = msg.body.labelIds || [];

return [{
  json: {
    skip: false,
    gmail_message_id: msg.body.id,
    gmail_thread_id: msg.body.threadId,
    subject,
    from_email: extractEmail(fromRaw),
    from_name: extractName(fromRaw),
    to_email: 'chellamma.uk@gmail.com',
    reply_to: getHeader('Reply-To'),
    date: date ? new Date(date).toISOString() : new Date().toISOString(),
    snippet: (msg.body.snippet || '').substring(0, 500),
    body_plain: bodyPlain.substring(0, 50000),
    body_html: bodyHtml.substring(0, 100000),
    body_stripped: bodyStripped,
    has_attachments: attachmentTypes.length > 0,
    attachment_types: attachmentTypes,
    has_ics_attachment: hasIcs,
    is_reply: isReply,
    in_reply_to: getHeader('In-Reply-To'),
    references_header: getHeader('References'),
    gmail_labels: gmailLabels,
    gmail_internal_date: msg.body.internalDate ? new Date(parseInt(msg.body.internalDate)).toISOString() : null,
    detected_language: detectedLanguage,
    language_confidence: languageConfidence
  }
}];
